.darma-loader-darma-custom-761 {
  color: var(--loader-color, #f59e0b);
  --loader-secondary-color: #fde68a;
  --loader-bg: #ffffff;
height: 15px;
aspect-ratio: 5;
display: grid;
animation: darma-loader-darma-custom-761-l36-0 2s infinite linear;
}
.darma-loader-darma-custom-761:before,
.darma-loader-darma-custom-761:after {
content: "";
grid-area: 1/1;
height: inherit;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: 15px 100%;
background-repeat: no-repeat;
animation: darma-loader-darma-custom-761-l36-1 1s infinite linear;
}
.darma-loader-darma-custom-761:after {
margin-left: auto;
--s:-1;
}
@keyframes darma-loader-darma-custom-761-l36-0 {
0%,49.99% {transform: scaleY( 1)}
50%,100% {transform: scaleY(-1)}
}
@keyframes darma-loader-darma-custom-761-l36-1 {
0% {transform:translate(0 ,calc(var(--s,1)*0px));aspect-ratio: 2.3}
33% {transform:translate(0 ,calc(var(--s,1)*8px));aspect-ratio: 2.3}
66% {transform:translate(calc(var(--s,1)*19px),calc(var(--s,1)*8px));aspect-ratio: 3.7}
100% {transform:translate(calc(var(--s,1)*19px),calc(var(--s,1)*0px));aspect-ratio: 3.7}
}

